import React from "react";
import "./App.css";
import Header from "./Componetns/Header/Header";

function App() {
  const loadExternal = () => {
      const script = document.createElement("script");
      script.src = '';
      script.async = true;
      document.body.appendChild(script);
    }
    return (
      <React.Fragment onLoad={loadExternal}>
            <Header />
        </React.Fragment>
    );
}

export default App;
